Rule.Source:
import sailpoint.tools.Util;
  import sailpoint.api.IdentityService;
  import sailpoint.object.Identity;
  import sailpoint.object.Application;
  import sailpoint.object.Link;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  Log logger = LogFactory.getLog("rule.Invision.Field.TPXID");

  logger.debug("Entering RACF-Invision Provisioning Policy Form Rule for Generating TPXID field Value");
  String racfName = null;
  if(identity != null){
    String type = "";
    Boolean duplicate=false;
    String firstName = identity.getFirstname();
    String lastName = identity.getLastname();
    String middleName = identity.getAttribute("middleInitial");
    String filteredFname = filterSpecialCharacter(firstName);
    String filteredLname = filterSpecialCharacter(lastName);
    String filteredMname = filterSpecialCharacter(middleName);

    IdentityService identityService =new IdentityService(context);                

    if(identity  != null && null != application){
      List racfLinks=identityService.getLinks(identity,application);
      if(null != racfLinks && !racfLinks.isEmpty()){
        Link racfLink=racfLinks.get(0);
		if(null != racfLink){
			racfName=racfLink.getAttribute("GenTPXID");
		}
      }
    }

    if (Util.isNotNullOrEmpty(filteredFname) && Util.isNotNullOrEmpty(filteredLname) && Util.isNullOrEmpty(racfName)){
      for(int i = 1; i < 100 ; i++){     
        racfName = "T4"+filteredFname.substring(0,1) + filteredLname.substring(0,1) + String.format("%02d", i);             
        duplicate = checkDuplicateTPXID(racfName);
        if(duplicate){
          continue;
          if(i == 99){
            type = "MiddleNameType";
            break;
          }
        }
        else{
          break;
        }      
      }

      if("MiddleNameType".equalsIgnoreCase(type) && Util.isNotNullOrEmpty(filteredMname)){
        racfName = "T4"+filteredFname.substring(0,1) + filteredLname.substring(0,1) + filteredMname.substring(0,1);            
        duplicate = checkDuplicateTPXID(racfName);  

        if(duplicate){
          type = "UserNameType";
          break;
        }
      }

      if("UserNameType".equalsIgnoreCase(type) && Util.isNotNullOrEmpty(filteredMname)){
        racfName = "T4"+filteredFname.substring(0,1) + filteredLname.substring(0,1) + filteredMname.substring(0,1);            
        duplicate = checkDuplicateTPXID(racfName);

        if(duplicate){
          type = "UserNameType";
          break;
        }
      }
    } 
  }

  logger.debug("Exiting RACF-Invision Provisioning Policy Form Rule for Generating TPXID field Value");
  return racfName;
